select d.*, de.name as device_name from detection d
left join device de on d.device_id = de.id
where d.id = #{id}

select d.*, de.name as device_name from detection d
left join device de on d.device_id = de.id
left join detection_result dr on d.id = dr.detection_id


        and d.device_id = #{deviceId}


        and d.timestamp >= #{startTime}


        and d.timestamp <= #{endTime}


        and dr.type = #{type}


group by d.id
order by d.timestamp desc
limit #{page}, #{size}

select count(distinct d.id) from detection d
left join detection_result dr on d.id = dr.detection_id


        and d.device_id = #{deviceId}


        and d.timestamp >= #{startTime}


        and d.timestamp <= #{endTime}


        and dr.type = #{type}
